mapper.select:
SELECT TOP 100 MODEL, STOCK, BOH, [INPUT], [OUT], EOH, (BOH + [INPUT] - [OUT]) AS CALC_EOH, EOH - (BOH + [INPUT] - [OUT]) AS DIFF FROM DOI_STOCK WHERE 1=1
AND YYYYMM = #{yyyymm}
AND SITE = #{site}
AND MODEL LIKE '%' + #{model} + '%'
ORDER BY ABS(EOH - (BOH + [INPUT] - [OUT])) DESC, MODEL, STOCK

SELECT COUNT(*) AS TOTAL_COUNT, SUM(CASE WHEN ABS(EOH - (BOH + [INPUT] - [OUT])) <= 0.01 THEN 1 ELSE 0 END) AS NORMAL_COUNT, SUM(CASE WHEN ABS(EOH - (BOH + [INPUT] - [OUT])) > 0.01 THEN 1 ELSE 0 END) AS ERROR_COUNT FROM DOI_STOCK WHERE 1=1
AND YYYYMM = #{yyyymm}
AND SITE = #{site}
AND MODEL LIKE '%' + #{model} + '%'

SELECT TOP 100 MODEL, 구분 AS GUBUN, EXPEN_SEL, BOH_AMT, IN_AMT, EOH_AMT, OUT_AMT, (BOH_AMT + IN_AMT - EOH_AMT) AS CALC_OUT_AMT, OUT_AMT - (BOH_AMT + IN_AMT - EOH_AMT) AS DIFF FROM DOI_STOCK_COST WHERE 1=1
AND YYYYMM = #{yyyymm}
AND SITE = #{site}
AND MODEL LIKE '%' + #{model} + '%'
ORDER BY ABS(OUT_AMT - (BOH_AMT + IN_AMT - EOH_AMT)) DESC, MODEL, GUBUN, EXPEN_SEL

SELECT COUNT(*) AS TOTAL_COUNT, SUM(CASE WHEN ABS(OUT_AMT - (BOH_AMT + IN_AMT - EOH_AMT)) <= 0.01 THEN 1 ELSE 0 END) AS NORMAL_COUNT, SUM(CASE WHEN ABS(OUT_AMT - (BOH_AMT + IN_AMT - EOH_AMT)) > 0.01 THEN 1 ELSE 0 END) AS ERROR_COUNT FROM DOI_STOCK_COST WHERE 1=1
AND YYYYMM = #{yyyymm}
AND SITE = #{site}
AND MODEL LIKE '%' + #{model} + '%'

SELECT TOP 100 MODEL, STOCK, BOH, EOH, CASE WHEN BOH < 0 AND EOH < 0 THEN '둘 다 음수' WHEN BOH < 0 THEN 'BOH 음수' WHEN EOH < 0 THEN 'EOH 음수' ELSE '정상' END AS ERROR_TYPE, CASE WHEN BOH < 0 AND EOH < 0 THEN '기초재고와 기말재고 모두 음수입니다.' WHEN BOH < 0 THEN '기초재고가 음수입니다.' WHEN EOH < 0 THEN '기말재고가 음수입니다.' ELSE '' END AS REMARK FROM DOI_STOCK WHERE 1=1
AND YYYYMM = #{yyyymm}
AND SITE = #{site}
AND MODEL LIKE '%' + #{model} + '%'
AND (BOH < 0 OR EOH < 0) ORDER BY CASE WHEN BOH < 0 AND EOH < 0 THEN 1 WHEN BOH < 0 THEN 2 WHEN EOH < 0 THEN 3 ELSE 4 END, MODEL, STOCK

SELECT COUNT(*) AS TOTAL_COUNT, SUM(CASE WHEN BOH >= 0 AND EOH >= 0 THEN 1 ELSE 0 END) AS NORMAL_COUNT, SUM(CASE WHEN BOH < 0 OR EOH < 0 THEN 1 ELSE 0 END) AS ERROR_COUNT FROM DOI_STOCK WHERE 1=1
AND YYYYMM = #{yyyymm}
AND SITE = #{site}
AND MODEL LIKE '%' + #{model} + '%'
